@app.route("/api/debug-pdf-texto", methods=["POST"])
def debug_pdf_texto():
    """Extrae texto de un PDF sin IA - para debug y desarrollo del parser"""
    try:
        if 'pdf' not in request.files:
            return jsonify({"ok": False, "error": "No se recibió PDF"})
        file = request.files['pdf']
        pdf_bytes = file.read()
        
        texto = ""
        # Intentar con pdfplumber
        try:
            import pdfplumber, io
            with pdfplumber.open(io.BytesIO(pdf_bytes)) as pdf:
                for i, page in enumerate(pdf.pages[:3]):  # max 3 páginas
                    t = page.extract_text()
                    if t:
                        texto += f"--- PÁGINA {i+1} ---\n{t}\n"
                    # También tablas
                    tables = page.extract_tables()
                    for j, table in enumerate(tables):
                        texto += f"--- TABLA {i+1}.{j+1} ---\n"
                        for row in table:
                            texto += " | ".join([str(c or "") for c in row]) + "\n"
        except Exception as e1:
            texto += f"pdfplumber error: {e1}\n"
            # Fallback con pypdf2
            try:
                import PyPDF2, io
                reader = PyPDF2.PdfReader(io.BytesIO(pdf_bytes))
                for i, page in enumerate(reader.pages[:3]):
                    texto += f"--- PÁGINA {i+1} ---\n{page.extract_text()}\n"
            except Exception as e2:
                texto += f"PyPDF2 error: {e2}\n"
        
        return jsonify({"ok": True, "nombre": file.filename, "texto": texto, "bytes": len(pdf_bytes)})
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)})


@app.route("/api/setup-sheets")
def setup_sheets():
    """Crea hojas necesarias si no existen"""
    try:
        service = get_sheets_service()
        meta = service.spreadsheets().get(spreadsheetId=SHEET_ID).execute()
        sheet_names = [s['properties']['title'] for s in meta.get('sheets',[])]
        creadas = []
        for nombre, cabecera in [
            ("Stock", ["Albaran","Fecha","Proveedor","Producto","TCult","Origen","Palets","Bultos","KgBrutos","KgNetos","FechaImport"]),
        ]:
            if nombre not in sheet_names:
                service.spreadsheets().batchUpdate(spreadsheetId=SHEET_ID, body={
                    "requests": [{"addSheet": {"properties": {"title": nombre}}}]
                }).execute()
                service.spreadsheets().values().update(
                    spreadsheetId=SHEET_ID, range=f"{nombre}!A1",
                    valueInputOption="RAW", body={"values": [cabecera]}
                ).execute()
                creadas.append(nombre)
        return jsonify({"ok": True, "hojas_existentes": sheet_names, "creadas": creadas})
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)})


@app.route("/api/test-anthropic")
def test_anthropic():
    """Test de conexión con Anthropic API - muestra error exacto"""
    import urllib.request as _ur, json as _j, os as _o
    key = _o.environ.get("ANTHROPIC_API_KEY","").strip()
    if not key:
        return jsonify({"api_ok": False, "error": "ANTHROPIC_API_KEY no encontrada", "key_length": 0})
    # Test con mensaje mínimo
    for model in ["claude-haiku-4-5-20251001", "claude-sonnet-4-6"]:
        try:
            payload = _j.dumps({
                "model": model,
                "max_tokens": 10,
                "messages": [{"role": "user", "content": "Di OK"}]
            }).encode()
            req = _ur.Request(
                "https://api.anthropic.com/v1/messages",
                data=payload,
                headers={"Content-Type":"application/json","x-api-key":key,"anthropic-version":"2023-06-01"},
                method="POST"
            )
            with _ur.urlopen(req, timeout=15) as r:
                data = _j.loads(r.read())
            return jsonify({"api_ok": True, "model": model, "key_length": len(key), "response": data["content"][0]["text"]})
        except Exception as e:
            err_body = ""
            if hasattr(e, 'read'):
                try: err_body = e.read().decode()
                except: pass
            if model == "claude-sonnet-4-6":
                return jsonify({"api_ok": False, "key_length": len(key), "error": str(e), "detail": err_body[:500]})
            continue

