MANIPULADO_SHEET = "Manipulado"

def ensure_manipulado_sheet():
    """Crear hoja Manipulado si no existe."""
    try:
        service = get_sheets_service()
        meta = service.spreadsheets().get(spreadsheetId=SHEET_ID).execute()
        nombres = [s['properties']['title'] for s in meta.get('sheets', [])]
        if MANIPULADO_SHEET not in nombres:
            service.spreadsheets().batchUpdate(
                spreadsheetId=SHEET_ID,
                body={"requests": [{"addSheet": {"properties": {"title": MANIPULADO_SHEET}}}]}
            ).execute()
            # Escribir cabecera
            service.spreadsheets().values().update(
                spreadsheetId=SHEET_ID, range=f"{MANIPULADO_SHEET}!A1",
                valueInputOption="RAW",
                body={"values": [["Fecha","Pedido","Producto","Cliente","Palet","Bultos","Lote","Personas","Estado","Inicio","Fin","Minutos","Destrio","Observaciones","FechaProc"]]}
            ).execute()
    except Exception as e:
        print(f"ensure_manipulado_sheet error: {e}")

