@app.route("/api/manipulado/cola")
def manipulado_cola():
    """Devuelve las líneas de manipulado para la fecha dada."""
    fecha = request.args.get("fecha", now_madrid().strftime("%d/%m/%Y"))
    try:
        service = get_sheets_service()
        result = service.spreadsheets().values().get(
            spreadsheetId=SHEET_ID, range=f"{MANIPULADO_SHEET}!A:O"
        ).execute()
        rows = result.get("values", [])
        if len(rows) < 2:
            return jsonify({"ok": True, "lineas": [], "fecha": fecha})

        headers = [h.lower().strip() for h in rows[0]]
        def col(name):
            try: return headers.index(name)
            except: return -1

        lineas = []
        for i, row in enumerate(rows[1:], start=2):
            def g(n, row=row):
                idx = col(n)
                return row[idx].strip() if idx >= 0 and idx < len(row) else ""

            f = g("fecha")
            if f != fecha:
                continue

            estado = g("estado") or "espera"
            if estado == "anulado":
                continue

            lineas.append({
                "row": i,
                "id": g("id"),
                "fecha": f,
                "pedido": g("pedido"),
                "producto": g("producto"),
                "cliente": g("cliente"),
                "palet": g("palet"),
                "bultos": g("bultos"),
                "linea": g("linea"),
                "estado": estado,
                "inicio": g("inicio"),
                "fin": g("fin"),
                "minutos": g("minutos"),
                "personas": g("personas") or "1",
                "observaciones": g("observaciones"),
                "lote": g("trazas"),
                "envase": g("envase") if "envase" in headers else "",
            })

        return jsonify({"ok": True, "lineas": lineas, "fecha": fecha})
    except Exception as e:
        import traceback
        return jsonify({"ok": False, "error": str(e), "trace": traceback.format_exc()[-400:]})


@app.route("/api/manipulado/asignar", methods=["POST"])
def manipulado_asignar():
    """Añadir todos los palets de un pedido a manipulado."""
    data = request.get_json() or {}
    pedido = str(data.get("pedido", "")).strip()
    if not pedido:
        return jsonify({"ok": False, "error": "Pedido requerido"})
    try:
        service = get_sheets_service()
        fecha = now_madrid().strftime("%d/%m/%Y")

        # Verificar si el pedido YA está en manipulado hoy (cualquier palet)
        existing = service.spreadsheets().values().get(
            spreadsheetId=SHEET_ID, range=f"{MANIPULADO_SHEET}!B:C"
        ).execute()
        ex_rows = existing.get("values", [])
        for ex_row in ex_rows[1:]:
            ex_fecha = ex_row[0].strip() if len(ex_row) > 0 else ""
            ex_pedido = ex_row[1].strip() if len(ex_row) > 1 else ""
            if ex_fecha == fecha and ex_pedido == pedido:
                return jsonify({"ok": False, "ya_existe": True,
                    "error": f"Pedido {pedido} ya está en manipulado hoy"})

        # Insertar 1 fila por palet
        import uuid
        palets = data.get("palets", [])  # lista de {num, bultos}
        if not palets:
            # Fallback: crear palets numerados
            n_palets = int(data.get("n_palets", 1))
            bultos_total = int(data.get("bultos", 0))
            bxp = round(bultos_total / n_palets) if n_palets > 0 else bultos_total
            palets = [{"num": i+1, "bultos": bxp} for i in range(n_palets)]

        # Leer cuántas filas hay para escribir en la siguiente
        count_res = service.spreadsheets().values().get(
            spreadsheetId=SHEET_ID, range=f"{MANIPULADO_SHEET}!A:A"
        ).execute()
        next_row = len(count_res.get("values", [])) + 1

        filas = []
        for p in palets:
            filas.append([
                str(uuid.uuid4())[:8].upper(),  # ID
                fecha,                           # Fecha
                pedido,                          # Pedido
                str(data.get("producto", "")),   # Producto
                str(data.get("cliente", "")),     # Cliente
                str(p.get("num", "")),           # Palet
                str(p.get("bultos", "")),         # Bultos
                "",                              # Linea (se asigna al iniciar)
                "espera",                        # Estado
                "", "", "",                      # Inicio, Fin, Minutos
                str(data.get("personas", "")),   # Personas
                str(data.get("observaciones", "")), # Observaciones
                "",                              # Trazas
            ])

        # Escribir todas las filas de golpe
        end_row = next_row + len(filas) - 1
        service.spreadsheets().values().update(
            spreadsheetId=SHEET_ID,
            range=f"{MANIPULADO_SHEET}!A{next_row}:O{end_row}",
            valueInputOption="RAW",
            body={"values": filas}
        ).execute()

        return jsonify({"ok": True, "palets_añadidos": len(filas)})
    except Exception as e:
        import traceback
        return jsonify({"ok": False, "error": str(e), "trace": traceback.format_exc()[-400:]})


@app.route("/api/manipulado/estado", methods=["POST"])
def manipulado_estado():
    """Actualizar estado de una línea de manipulado."""
    data = request.get_json() or {}
    row = data.get("row")
    if not row:
        return jsonify({"ok": False, "error": "Row requerido"})
    try:
        service = get_sheets_service()
        # Leer cabecera para saber columnas
        result = service.spreadsheets().values().get(
            spreadsheetId=SHEET_ID, range=f"{MANIPULADO_SHEET}!A1:P1"
        ).execute()
        headers = [h.lower().strip() for h in (result.get("values", [[]])[0])]

        def col_letter(name):
            try:
                idx = headers.index(name)
                return chr(65 + idx)  # A=0, B=1...
            except:
                return None

        updates = []
        estado = data.get("estado")
        if estado:
            c = col_letter("estado")
            if c:
                updates.append({"range": f"{MANIPULADO_SHEET}!{c}{row}", "values": [[estado]]})
        inicio = data.get("inicio")
        if inicio:
            c = col_letter("inicio")
            if c:
                updates.append({"range": f"{MANIPULADO_SHEET}!{c}{row}", "values": [[inicio]]})
        fin = data.get("fin")
        if fin:
            c = col_letter("fin")
            if c:
                updates.append({"range": f"{MANIPULADO_SHEET}!{c}{row}", "values": [[fin]]})
        minutos = data.get("minutos")
        if minutos is not None:
            c = col_letter("minutos")
            if c:
                updates.append({"range": f"{MANIPULADO_SHEET}!{c}{row}", "values": [[str(minutos)]]})
        personas = data.get("personas")
        if personas is not None:
            c = col_letter("personas")
            if c:
                updates.append({"range": f"{MANIPULADO_SHEET}!{c}{row}", "values": [[str(personas)]]})
        observaciones = data.get("observaciones")
        if observaciones is not None:
            c = col_letter("observaciones")
            if c:
                updates.append({"range": f"{MANIPULADO_SHEET}!{c}{row}", "values": [[str(observaciones)]]})
        lote = data.get("lote")
        if lote is not None:
            c = col_letter("trazas")  # en la hoja se llama Trazas
            if c:
                updates.append({"range": f"{MANIPULADO_SHEET}!{c}{row}", "values": [[lote]]})
        palet = data.get("palet")
        if palet is not None:
            c = col_letter("palet")
            if c:
                updates.append({"range": f"{MANIPULADO_SHEET}!{c}{row}", "values": [[str(palet)]]})
        linea = data.get("linea")
        if linea is not None:
            c = col_letter("linea")
            if c:
                updates.append({"range": f"{MANIPULADO_SHEET}!{c}{row}", "values": [[str(linea)]]})

        if updates:
            service.spreadsheets().values().batchUpdate(
                spreadsheetId=SHEET_ID,
                body={"valueInputOption": "RAW", "data": updates}
            ).execute()
        return jsonify({"ok": True})
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)})


