@app.route("/api/manipulado/destrio", methods=["POST"])
def manipulado_destrio():
    """Registrar destrío rápido."""
    data = request.get_json() or {}
    try:
        service = get_sheets_service()
        fecha = now_madrid().strftime("%d/%m/%Y")  # Siempre fecha de hoy, no fecha salida

        # Verificar si ya existe este pedido en manipulado hoy
        # Estructura: A=ID, B=Fecha, C=Pedido
        existing = service.spreadsheets().values().get(
            spreadsheetId=SHEET_ID, range=f"{MANIPULADO_SHEET}!A:C"
        ).execute()
        ex_rows = existing.get("values", [])
        palet_nuevo = str(data.get("palet", "")).strip()
        for ex_row in ex_rows[1:]:
            ex_fecha = ex_row[1].strip() if len(ex_row) > 1 else ""
            ex_pedido = ex_row[2].strip() if len(ex_row) > 2 else ""
            ex_palet = ex_row[5].strip() if len(ex_row) > 5 else ""
            # Solo bloquear si mismo pedido Y mismo número de palet
            if ex_fecha == fecha and ex_pedido == pedido and ex_palet == palet_nuevo and palet_nuevo:
                return jsonify({"ok": False, "error": f"El pedido {pedido} palet {palet_nuevo} ya está en manipulado", "ya_existe": True})

        fila = [
            fecha,
            data.get("pedido", "DESTRIO"),
            data.get("producto", ""),
            "",  # cliente
            "",  # palet
            "",  # bultos
            "",  # lote
            "",  # personas
            "destrio",
            "", "", "",
            str(data.get("kilos", 0)),
            data.get("motivo", ""),
            now_madrid().strftime("%d/%m/%Y %H:%M")
        ]
        service.spreadsheets().values().append(
            spreadsheetId=SHEET_ID, range=f"{MANIPULADO_SHEET}!A:P",
            valueInputOption="RAW", insertDataOption="INSERT_ROWS",
            body={"values": [fila]}
        ).execute()
        return jsonify({"ok": True})
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)})


# ===== STOCK =====
@app.route("/api/stock")
def stock():
    """Devuelve datos de stock calculados desde la hoja Stock."""
    try:
        service = get_sheets_service()
        result = service.spreadsheets().values().get(
            spreadsheetId=SHEET_ID, range="Stock!A:K"
        ).execute()
        rows = result.get("values", [])
        if len(rows) < 2:
            return jsonify({"ok": True, "resumen": [], "detalle": [], "total_palets": 0, "total_bultos": 0, "ultima_import": ""})

        headers = [h.lower().strip() for h in rows[0]]
        def col(name):
            for h in [name, name.replace(" ",""), name.replace("_","")]:
                try: return headers.index(h)
                except: pass
            return -1

        # Agrupar por producto
        from collections import defaultdict
        por_producto = defaultdict(lambda: {"palets": 0, "bultos": 0, "kg_brutos": 0, "kg_netos": 0, "entradas": 0})
        ultima = ""
        detalle = []

        for row in rows[1:]:
            def g(n):
                i = col(n)
                return row[i].strip() if i >= 0 and i < len(row) else ""

            producto = g("producto") or g("prod")
            if not producto:
                continue

            def num(v):
                try: return float(str(v).replace(",", ".").replace(" ","")) 
                except: return 0.0

            palets = num(g("palets"))
            bultos = num(g("bultos"))
            kg_b = num(g("kgbrutos") or g("kg brutos") or g("kg_brutos"))
            kg_n = num(g("kgnetos") or g("kg netos") or g("kg_netos"))
            fecha_imp = g("fechaimport") or g("fecha import") or g("fecha_import")

            por_producto[producto]["palets"] += palets
            por_producto[producto]["bultos"] += bultos
            por_producto[producto]["kg_brutos"] += kg_b
            por_producto[producto]["kg_netos"] += kg_n
            por_producto[producto]["entradas"] += 1
            if fecha_imp > ultima:
                ultima = fecha_imp

            detalle.append({
                "albaran": g("albaran"),
                "fecha": g("fecha"),
                "proveedor": g("proveedor"),
                "producto": producto,
                "tcult": g("tcult"),
                "origen": g("origen"),
                "palets": palets,
                "bultos": bultos,
                "kg_brutos": kg_b,
                "kg_netos": kg_n,
            })

        resumen = []
        for prod, datos in sorted(por_producto.items()):
            resumen.append({
                "producto": prod,
                "palets": round(datos["palets"], 1),
                "bultos": int(datos["bultos"]),
                "kg_brutos": round(datos["kg_brutos"], 1),
                "kg_netos": round(datos["kg_netos"], 1),
                "entradas": datos["entradas"],
            })

        total_palets = sum(r["palets"] for r in resumen)
        total_bultos = sum(r["bultos"] for r in resumen)

        return jsonify({
            "ok": True,
            "resumen": resumen,
            "detalle": detalle,
            "total_palets": round(total_palets, 1),
            "total_bultos": total_bultos,
            "ultima_import": ultima,
            "n_productos": len(resumen)
        })
    except Exception as e:
        import traceback
        return jsonify({"ok": False, "error": str(e), "trace": traceback.format_exc()[-400:]})


@app.route("/api/stock/importar", methods=["POST"])
def stock_importar():
    """Importa CSV de Orizon a la hoja Stock."""
    if "csv" not in request.files:
        return jsonify({"ok": False, "error": "No se recibió archivo"})
    f = request.files["csv"]
    try:
        import io as _io3, csv as _csv3
        raw = f.read().decode("utf-8", errors="replace")
        primera = raw.split("\n")[0]
        sep = ";" if primera.count(";") > primera.count(",") else ","
        reader = _csv3.DictReader(_io3.StringIO(raw), delimiter=sep)
        raw_headers = reader.fieldnames or []
        col_map = {h: h.strip().lower() for h in raw_headers}

        def get(row, *keys):
            for k in keys:
                for orig, clean in col_map.items():
                    if clean == k.lower():
                        v = row.get(orig, "").strip()
                        if v: return v
            return ""

        fecha_imp = now_madrid().strftime("%d/%m/%Y %H:%M")
        filas = []
        for row in reader:
            prod = get(row, "producto", "product", "articulo", "descripcion")
            if not prod:
                continue
            filas.append([
                get(row, "albaran", "albarán", "num albaran", "numero albaran"),
                get(row, "fecha", "date", "fecha entrada"),
                get(row, "proveedor", "supplier", "origen proveedor"),
                prod,
                get(row, "tcult", "t.cult", "tipo cult", "ecobio", "categoria"),
                get(row, "origen", "pais", "country"),
                get(row, "palets", "pallets", "n palets"),
                get(row, "bultos", "cajas", "boxes"),
                get(row, "kg brutos", "kgbrutos", "kg_brutos", "peso bruto", "gross weight"),
                get(row, "kg netos", "kgnetos", "kg_netos", "peso neto", "net weight"),
                fecha_imp,
            ])

        if not filas:
            return jsonify({"ok": False, "error": "No se encontraron líneas válidas en el CSV"})

        service = get_sheets_service()
        service.spreadsheets().values().append(
            spreadsheetId=SHEET_ID, range="Stock!A:K",
            valueInputOption="RAW", insertDataOption="INSERT_ROWS",
            body={"values": filas}
        ).execute()
        return jsonify({"ok": True, "importadas": len(filas)})
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)})


